mapper.update:
UPDATE COURSE
   SET COURSE_NM      = #{courseNm}
     , COURSE_INFO    = #{courseInfo}
     , COURSE_PATH_NM = #{coursePathNm}
     , COURSE_DSTNC   = #{courseDstnc}
     , COURSE_REQ_TM  = #{courseReqTm}
 WHERE COURSE_NO      = #{courseNo}

UPDATE COURSE
SET COURSE_INQ_CNT = NVL(COURSE_INQ_CNT, 0) + 1
WHERE COURSE_NO = #{courseNo}
